import{_ as e,o,c as r,ag as a}from"./chunks/framework.BYehg5q7.js";const g=JSON.parse('{"title":"Guided Tour","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tour.md","filePath":"guide/tour.md","lastUpdated":1772287587000}'),i={name:"guide/tour.md"};function s(l,t,n,u,h,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="guided-tour" tabindex="-1">Guided Tour <a class="header-anchor" href="#guided-tour" aria-label="Permalink to &quot;Guided Tour&quot;">​</a></h1><p>The guided tour is a step-by-step walkthrough that introduces the main features of getbased. The page dims and a spotlight highlights one element at a time, with a tooltip explaining what it does.</p><h2 id="the-app-tour-7-steps" tabindex="-1">The App Tour (7 Steps) <a class="header-anchor" href="#the-app-tour-7-steps" aria-label="Permalink to &quot;The App Tour (7 Steps)&quot;">​</a></h2><p>The main tour covers seven stops:</p><ol><li><strong>Welcome</strong> — A brief introduction to getbased</li><li><strong>Drop Zone</strong> — Where to import your lab PDFs or JSON files</li><li><strong>Sidebar Navigation</strong> — How to move between biomarker categories</li><li><strong>Context Cards</strong> — The lifestyle cards that give AI analysis more context</li><li><strong>Settings</strong> — Where to set your profile, units, AI provider, and privacy options</li><li><strong>Send Feedback</strong> — How to report bugs or suggest features</li><li><strong>Ask AI</strong> — The chat panel for asking questions about your results</li></ol><h2 id="auto-trigger-on-first-visit" tabindex="-1">Auto-Trigger on First Visit <a class="header-anchor" href="#auto-trigger-on-first-visit" aria-label="Permalink to &quot;Auto-Trigger on First Visit&quot;">​</a></h2><p>The tour starts automatically the first time you open the dashboard. It will not run again after you complete or skip it — getbased remembers your progress.</p><h2 id="navigating-the-tour" tabindex="-1">Navigating the Tour <a class="header-anchor" href="#navigating-the-tour" aria-label="Permalink to &quot;Navigating the Tour&quot;">​</a></h2><ul><li>Click <strong>Next</strong> to advance to the next step</li><li>Click <strong>Back</strong> to return to the previous step</li><li>Click <strong>Skip</strong> or press <strong>Escape</strong> to exit the tour at any point</li><li>Progress dots at the bottom of the tooltip show where you are in the sequence</li><li>Click the dimmed overlay to dismiss the tour</li></ul><h2 id="restarting-the-tour" tabindex="-1">Restarting the Tour <a class="header-anchor" href="#restarting-the-tour" aria-label="Permalink to &quot;Restarting the Tour&quot;">​</a></h2><p>If you want to take the tour again, go to <strong>Settings → Display</strong> and click <strong>Take a Tour</strong>. This restarts the tour from the beginning regardless of whether you completed it before.</p><h2 id="cycle-tour-8-steps" tabindex="-1">Cycle Tour (8 Steps) <a class="header-anchor" href="#cycle-tour-8-steps" aria-label="Permalink to &quot;Cycle Tour (8 Steps)&quot;">​</a></h2><p>A separate tour covers the menstrual cycle tracking features. It is available for female profiles and covers:</p><ol><li>Welcome to cycle features</li><li>The cycle summary card</li><li>Recommended next blood draw date</li><li>Phase badges on your lab dates</li><li>Period log</li><li>Cycle-specific alerts (heavy flow, iron, perimenopause)</li><li>Cycle phase bands in the Layers dropdown</li><li>Asking the AI about cycle-related results</li></ol><p><strong>The cycle tour starts automatically</strong> the first time you save your menstrual cycle data. You can also re-trigger it at any time by clicking the <strong>?</strong> button in the cycle section header on the dashboard.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Even if you dismiss a tour early, you can always restart it. The app tour is in Settings → Display; the cycle tour is the ? button in the cycle section.</p></div>',16)])])}const p=e(i,[["render",s]]);export{g as __pageData,p as default};
